const payload = $json.body ?? $json;
const businessType = String(payload.business_type ?? payload.businessType ?? '').trim();
const serviceArea = String(payload.service_area ?? payload.serviceArea ?? '').trim();
const clientName = String(payload.client_name ?? payload.clientName ?? '').trim();
const keywords = Array.isArray(payload.keywords) ? payload.keywords.map(String).filter(Boolean) : [];
const requestedSources = Array.isArray(payload.sources) && payload.sources.length ? payload.sources.map(String) : ['web', 'reddit', 'forums', 'linkedin_manual', 'facebook_manual'];

if (!businessType) {
  throw new Error('business_type is required.');
}

const safeSources = requestedSources.map((source) => {
  const normalized = source.toLowerCase().replace(/\s+/g, '_');
  if (['linkedin', 'linkedin_scrape'].includes(normalized)) return 'linkedin_manual';
  if (['facebook', 'facebook_scrape'].includes(normalized)) return 'facebook_manual';
  return normalized;
});

const baseTerms = [businessType, serviceArea, ...keywords].filter(Boolean).join(' ');
const jobs = safeSources.map((source) => {
  const queryBySource = {
    web: `${baseTerms} contact owner business needs`,
    reddit: `site:reddit.com ${baseTerms} recommendations pain points`,
    forums: `${baseTerms} forum recommendations problems business owner`,
    linkedin_manual: `${baseTerms} LinkedIn company founder hiring growth`,
    facebook_manual: `${baseTerms} Facebook group business recommendations`
  };

  return {
    source,
    mode: source.includes('manual') ? 'manual_or_official_api_only' : 'public_search_api',
    query: queryBySource[source] ?? baseTerms,
    compliance_note: source.includes('manual')
      ? 'Do not scrape logged-in pages. Use official APIs, exports, or manual review.'
      : 'Use public search APIs and respect robots.txt, rate limits, and source terms.',
    desired_output: ['name', 'business_name', 'public_profile_url', 'reason_matched', 'source', 'confidence', 'recommended_next_step']
  };
});

return [{
  json: {
    agent: 'OBMC Lead Discovery Agent',
    client_name: clientName || null,
    business_type: businessType,
    service_area: serviceArea || null,
    keywords,
    jobs,
    next_step: 'Connect a compliant search provider/API credential, then add source-specific fetch and scoring nodes.',
    created_at: new Date().toISOString()
  }
}];

const jobs = $json.jobs ?? [];
const scoringRules = {
  high: ['explicit need', 'hiring', 'asking for recommendations', 'recent complaint', 'clear business fit'],
  medium: ['business type match', 'recent public activity', 'location match'],
  reject: ['private profile only', 'no business relevance', 'no public contact path', 'restricted source']
};

return [{
  json: {
    ...$json,
    scoring_rules: scoringRules,
    output_policy: {
      no_passworded_or_logged_in_scraping: true,
      no_contact_enrichment_without_lawful_basis: true,
      create_ghl_contact_only_after_review: true,
      preserve_source_url: true
    },
    ready_for_fetch_nodes: jobs.length > 0
  }
}];
